{"name": "", "cron": "", "period": 0, "script": "
original_temp = (#WineCellar #TemperatureSensor).temperatureSensor_temperature

delay(10 MIN)

temp = (#WineCellar #TemperatureSensor).temperatureSensor_temperature

if (temp >= original_temp + 1 or temp <= original_temp - 1) {

    (#Speaker).speaker_speak("와인셀러의 온도가 급변했습니다")
}"}

{"name": "", "cron": "0 18 * * *", "period": 0, "script": "
menu = (#MenuProvider).menuProvider_getMenu("오늘 학생식당 저녁")

(#Speaker).speaker_speak("오늘 학생 식당의 저녁 메뉴는" + menu + "입니다")"}

{"name": "", "cron": "0 23 * * *", "period": 0, "script": "
if ((#Safe).safe_safeState == "unlocked" or (#DoorLock).doorLock_doorLockState == "unlocked") {

    (#Speaker).speaker_speak("금고와 도어락의 잠금 상태를 확인해 주세요.")

}"}

{"name": "", "cron": "", "period": 3600000, "script": "
open := false

if (open == false) {

    (#Door).door_open()

    open = true

} else {

    (#Door).door_close()

    open = false

}"}

{"name": "", "cron": "0 13 * * *", "period": 300000, "script": "
if ((#Clock).clock_hour == 15) {
    break
}
open := false
if (open == false) {
    (#Valve).valve_open()
    open = true
} else {
    (#Valve).valve_close()
    open = false
}"}

{"name": "", "cron": "", "period": 600000, "script": "
open := false

if (open == false) {

    (#Window).windowCovering_upOrOpen()

    open = true

} else {

    (#Window).windowCovering_downOrClose()

    open = false

}"}

